def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, m = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 初始化：随机选择k个点
    indices = list(range(n))
    selected = set(random.sample(indices, k))
    unselected = set(indices) - selected

    # 计算初始超体积
    def compute_hv(indices_set):
        if not indices_set:
            return 0.0
        pts = points[list(indices_set)]
        hv = pg.hypervolume(pts)
        return hv.compute(reference_point)

    current_hv = compute_hv(selected)

    # 进化优化循环
    max_iterations = 100
    no_improve_count = 0

    for iteration in range(max_iterations):
        improved = False

        # 阶段1: 定向突变 - 移除贡献最小的点，加入随机未选点
        if random.random() < 0.7:  # 70%概率执行定向突变
            # 计算每个选中点的边际贡献
            contributions = {}
            for s in list(selected):
                temp_set = selected - {s}
                hv_without = compute_hv(temp_set)
                contributions[s] = current_hv - hv_without

            # 找到贡献最小的点
            worst = min(contributions.items(), key=lambda x: x[1])[0]

            # 从未选点中随机选择一个
            if unselected:
                new_point = random.choice(list(unselected))

                # 尝试替换
                new_set = (selected - {worst}) | {new_point}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    selected = new_set
                    unselected = (unselected - {new_point}) | {worst}
                    current_hv = new_hv
                    improved = True

        # 阶段2: 局部搜索 - 尝试所有可能的单点交换
        if not improved:
            best_swap = None
            best_hv = current_hv

            for s in list(selected):
                for u in list(unselected):
                    # 尝试交换
                    new_set = (selected - {s}) | {u}
                    new_hv = compute_hv(new_set)

                    if new_hv > best_hv:
                        best_hv = new_hv
                        best_swap = (s, u)

            if best_swap:
                s_remove, u_add = best_swap
                selected = (selected - {s_remove}) | {u_add}
                unselected = (unselected - {u_add}) | {s_remove}
                current_hv = best_hv
                improved = True

        # 阶段3: 随机扰动 - 小概率执行双点交换
        if not improved and random.random() < 0.3:
            if len(selected) >= 2 and len(unselected) >= 2:
                # 随机选择两个选中点和两个未选点
                s1, s2 = random.sample(list(selected), 2)
                u1, u2 = random.sample(list(unselected), 2)

                # 尝试双交换
                new_set = (selected - {s1, s2}) | {u1, u2}
                new_hv = compute_hv(new_set)

                if new_hv > current_hv:
                    selected = new_set
                    unselected = (unselected - {u1, u2}) | {s1, s2}
                    current_hv = new_hv
                    improved = True

        # 检查终止条件
        if improved:
            no_improve_count = 0
        else:
            no_improve_count += 1

        if no_improve_count >= 10:
            break

    # 返回最终选择的点
    return points[list(selected)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape
    selected_indices = []
    selected_points = []

    # 预计算所有点的超体积贡献缓存
    contribution_cache = {}

    def compute_hypervolume(points_list: List[np.ndarray]) -> float:
        """计算点集的超体积"""
        if not points_list:
            return 0.0
        hv = pg.hypervolume(np.array(points_list))
        return hv.compute(reference_point)

    def point_contribution(idx: int, current_set: List[int]) -> float:
        """计算点idx对当前集合的超体积贡献（带缓存）"""
        cache_key = (idx, tuple(sorted(current_set)))
        if cache_key in contribution_cache:
            return contribution_cache[cache_key]

        if not current_set:
            contrib = compute_hypervolume([points[idx]])
        else:
            current_points = [points[i] for i in current_set]
            hv_before = compute_hypervolume(current_points)
            hv_after = compute_hypervolume(current_points + [points[idx]])
            contrib = hv_after - hv_before

        contribution_cache[cache_key] = contrib
        return contrib

    # 使用锦标赛选择加速贪心过程
    tournament_size = min(50, n)

    for _ in range(k):
        best_idx = -1
        best_contrib = -np.inf

        # 锦标赛选择：随机采样一部分候选点进行评估
        candidates = np.random.choice([i for i in range(n) if i not in selected_indices], 
                                     size=min(tournament_size, n - len(selected_indices)), 
                                     replace=False)

        for idx in candidates:
            contrib = point_contribution(idx, selected_indices)
            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        # 如果锦标赛没找到，回退到全局搜索
        if best_idx == -1:
            for idx in range(n):
                if idx not in selected_indices:
                    contrib = point_contribution(idx, selected_indices)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx

        selected_indices.append(best_idx)
        selected_points.append(points[best_idx])

        # 定期清理缓存以避免内存爆炸
        if len(contribution_cache) > 10000:
            # 保留最近使用的条目
            contribution_cache = {k: v for k, v in list(contribution_cache.items())[-5000:]}

    return np.array(selected_points)

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 辅助函数：计算点集的超体积
    def compute_hypervolume(point_set: List[np.ndarray]) -> float:
        if not point_set:
            return 0.0
        hv = pg.hypervolume(np.array(point_set))
        return hv.compute(reference_point)

    # 阶段1: 贪心选择（带贡献缓存）
    selected_indices = []
    selected_points = []
    contribution_cache = {}

    # 预计算所有点的独立超体积
    independent_hv = {}
    for i in range(n):
        independent_hv[i] = compute_hypervolume([points[i]])

    while len(selected_indices) < k:
        best_idx = -1
        best_contrib = -np.inf

        # 遍历所有未选中的点
        for idx in range(n):
            if idx in selected_indices:
                continue

            # 计算贡献（带缓存）
            cache_key = (idx, tuple(sorted(selected_indices)))
            if cache_key in contribution_cache:
                contrib = contribution_cache[cache_key]
            else:
                if not selected_indices:
                    contrib = independent_hv[idx]
                else:
                    current_points = [points[i] for i in selected_indices]
                    hv_before = compute_hypervolume(current_points)
                    hv_after = compute_hypervolume(current_points + [points[idx]])
                    contrib = hv_after - hv_before
                contribution_cache[cache_key] = contrib

            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        # 添加选中的点
        selected_indices.append(best_idx)
        selected_points.append(points[best_idx])

    # 阶段2: 局部搜索优化（交换操作）
    improved = True
    max_iterations = 100

    for _ in range(max_iterations):
        if not improved:
            break

        improved = False

        # 尝试交换操作：用未选中的点替换选中的点
        for i in range(k):
            sel_idx = selected_indices[i]
            current_hv = compute_hypervolume(selected_points)

            # 找到最佳替换
            best_swap_idx = -1
            best_swap_improvement = 0

            for cand_idx in range(n):
                if cand_idx in selected_indices:
                    continue

                # 临时创建新集合
                temp_points = selected_points.copy()
                temp_points[i] = points[cand_idx]
                new_hv = compute_hypervolume(temp_points)

                improvement = new_hv - current_hv
                if improvement > best_swap_improvement:
                    best_swap_improvement = improvement
                    best_swap_idx = cand_idx

            # 执行交换
            if best_swap_idx != -1 and best_swap_improvement > 1e-10:
                selected_indices[i] = best_swap_idx
                selected_points[i] = points[best_swap_idx]
                improved = True
                break  # 一次只进行一次交换，然后重新评估

    return np.array(selected_points)
